choose.when:
select id, title, intro as description, cover, null as url, null as author, null as submit_time, level, status, create_by, create_time from osh_course where delete_flag = 0 and status = 0
and (title like concat('%', #{keyword}, '%') or intro like concat('%', #{keyword}, '%'))
order by create_time desc, id desc limit #{offset}, #{pageSize}

select id, content as title, content as description, null as cover, null as url, null as author, null as submit_time, level, status, create_by, create_time from osh_question_answer_question where delete_flag = 0 and status = 0
and content like concat('%', #{keyword}, '%')
order by create_time desc, id desc limit #{offset}, #{pageSize}

select id, content as title, content as description, null as cover, null as url, null as author, null as submit_time, level, status, create_by, create_time from osh_question_answer_answer where delete_flag = 0 and status = 0
and content like concat('%', #{keyword}, '%')
order by create_time desc, id desc limit #{offset}, #{pageSize}

select id, title, description, cover, null as url, null as author, null as submit_time, level, cast(status as signed) as status, create_by, create_time from osh_book where del_flag = '0' and status = '0'
and (title like concat('%', #{keyword}, '%') or description like concat('%', #{keyword}, '%'))
order by create_time desc, id desc limit #{offset}, #{pageSize}

select id, tool_name as title, description, logo_url as cover, route_path as url, null as author, null as submit_time, level, status, create_by, create_time from osh_tool where delete_flag = 0 and status = 0
and (tool_name like concat('%', #{keyword}, '%') or description like concat('%', #{keyword}, '%'))
order by create_time desc, id desc limit #{offset}, #{pageSize}

select id, name as title, description, logo_url as cover, url, null as author, null as submit_time, level, status, create_by, create_time from osh_practical_website where delete_flag = 0 and status = 0
and (name like concat('%', #{keyword}, '%') or description like concat('%', #{keyword}, '%') or url like concat('%', #{keyword}, '%'))
order by create_time desc, id desc limit #{offset}, #{pageSize}

select id, project_name as title, project_desc as description, project_cover as cover, project_url as url, author_name as author, create_time as submit_time, null as level, status, create_by, create_time from osh_open_project where delete_flag = 0 and status = 0
and (project_name like concat('%', #{keyword}, '%') or project_desc like concat('%', #{keyword}, '%') or project_url like concat('%', #{keyword}, '%') or author_name like concat('%', #{keyword}, '%'))
order by create_time desc, id desc limit #{offset}, #{pageSize}

select id, title, content as description, null as cover, null as url, null as author, create_time as submit_time, null as level, status, null as create_by, create_time from osh_info_gap where delete_flag = 0 and status = 0
and (title like concat('%', #{keyword}, '%') or content like concat('%', #{keyword}, '%') or tag like concat('%', #{keyword}, '%'))
order by create_time desc, id desc limit #{offset}, #{pageSize}
